const utils = require('../utils/beatmaps');
const Collection = require('./collection');
const Beatmap = require('./beatmap');

class Beatmapset {
    constructor(info) {
        this.difficulties = new Collection;
        info.map(diff => this.difficulties.set(diff.version, new Beatmap(diff)));
        // this.difficulties = 
        //     info.map(diff => new Difficulty(diff));
        utils.mergeInfo(info[0], this);
        this.ID = Number(info.beatmapsetID);
    }
}

module.exports = Beatmapset;